// ================================================================
// canchas-list.component.ts — Lista y Gestión de Canchas
// ================================================================
// Este es el componente más complejo del frontend.
// Para el ADMIN muestra el panel de gestión completo (CRUD).
// Para el CLIENTE muestra solo el listado con el botón de reservar.
//
// FUNCIONALIDADES:
// ✅ Listado con paginación server-side (el backend devuelve solo X registros)
// ✅ Buscador por nombre en tiempo real
// ✅ Modal de creación/edición de canchas (solo Admin)
// ✅ Confirmación de eliminación (solo Admin)
// ✅ Botón de reserva rápida (solo Cliente)
// ✅ Mensajes de éxito y error con auto-dismiss
// ================================================================
import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { CanchasService } from '../../../services/canchas.service';
import { ReservasService } from '../../../services/reservas.service';
import { AuthService } from '../../../services/auth.service';
import { Cancha } from '../../../models/cancha';
import { ReservaCreate } from '../../../models/reserva';

@Component({
  selector: 'app-canchas-list',
  templateUrl: './canchas-list.component.html',
  styleUrls: ['./canchas-list.component.css']
})
export class CanchasListComponent implements OnInit {

  // ============================================================
  // PROPIEDADES DEL COMPONENTE
  // ============================================================

  // Array que guarda las canchas devueltas por el backend
  canchas: Cancha[] = [];

  // Variables para la PAGINACIÓN SERVER-SIDE
  totalItems: number = 0;     // Total de canchas en la BD (para calcular # de páginas)
  page: number = 1;           // Página actual (empieza en 1)
  pageSize: number = 5;       // Canchas por página

  // Texto del buscador por nombre
  searchTerm: string = '';

  // Estado de la pantalla
  isLoading: boolean = false;   // true mientras espera al backend
  userRole: string | null = ''; // 'Admin' o 'Cliente'

  // Mensajes de feedback para el usuario
  mensajeExito: string = '';
  mensajeError: string = '';

  // ============================================================
  // PROPIEDADES DEL MODAL DE CREAR/EDITAR CANCHAS (Solo Admin)
  // ============================================================

  // Controla si el modal está visible o no
  showModal: boolean = false;

  // Indica si el modal está en modo "Crear" o "Editar"
  // null = Crear nueva cancha, número = Editar la cancha con ese Id
  editingId: number | null = null;

  // Título dinámico del modal
  modalTitle: string = 'Nueva Cancha';

  // Formulario del modal
  canchaForm: FormGroup;

  // true mientras se envía el formulario del modal
  isSaving: boolean = false;

  // ============================================================
  // PROPIEDADES DEL MODAL DE CONFIRMACIÓN DE ELIMINACIÓN
  // ============================================================
  showDeleteModal: boolean = false; // ¿Mostrar el modal de confirmar eliminación?
  deletingCancha: Cancha | null = null; // La cancha que se está intentando eliminar
  isDeleting: boolean = false; // true mientras se espera la respuesta del DELETE

  // ============================================================
  // PROPIEDADES DEL MODAL DE RESERVACIÓN
  // ============================================================
  showReservaModal: boolean = false;
  selectedCancha: Cancha | null = null;
  reservaForm: FormGroup;

  // Constructor: Angular inyecta los servicios automáticamente
  constructor(
    private fb: FormBuilder,
    private canchasService: CanchasService,
    private reservasService: ReservasService,
    private authService: AuthService
  ) {
    // Definimos el formulario de la cancha con sus validaciones
    this.canchaForm = this.fb.group({
      nombre: ['', [Validators.required, Validators.maxLength(100)]],
      descripcion: ['', Validators.maxLength(500)],
      // Validators.min(1) = el precio debe ser mayor que 0
      precioPorHora: ['', [Validators.required, Validators.min(1)]]
    });

    // Definimos el formulario de la reserva con sus validaciones
    this.reservaForm = this.fb.group({
      fecha: ['', Validators.required],
      horaInicio: ['', Validators.required],
      horaFin: ['', Validators.required]
    });
  }

  // ============================================================
  // ngOnInit: Se ejecuta automáticamente cuando el componente se monta
  // ============================================================
  ngOnInit(): void {
    // Obtenemos el rol del usuario desde el localStorage (guardado al hacer login)
    this.userRole = this.authService.getRole();
    // Cargamos las canchas del backend al abrir la pantalla
    this.cargarCanchas();
  }

  // Getter para acceso rápido a los controles del formulario del modal
  get f() {
    return this.canchaForm.controls;
  }

  // ============================================================
  // CARGAR CANCHAS (con paginación y búsqueda)
  // ============================================================
  // Este método llama al backend con los parámetros de búsqueda y paginación.
  // El backend devuelve SOLO las canchas de la página actual, no todas.
  cargarCanchas(): void {
    this.isLoading = true; // Activamos el spinner
    // Llamamos al servicio que hace GET /api/canchas?nombre=X&page=Y&pageSize=Z
    this.canchasService.getCanchas(this.searchTerm, this.page, this.pageSize).subscribe({
      next: (data) => {
        // La respuesta del backend tiene esta estructura:
        // { totalItems: 10, page: 1, pageSize: 5, items: [...] }
        this.canchas = data.items;        // Las canchas de ESTA página
        this.totalItems = data.totalItems; // El total global para calcular # de páginas
        this.isLoading = false;
      },
      error: (err) => {
        this.isLoading = false;
        this.mostrarError('Error al cargar las canchas. Intenta de nuevo.');
      }
    });
  }

  // ============================================================
  // BÚSQUEDA
  // ============================================================
  buscar(): void {
    // Al buscar, siempre volvemos a la página 1 para ver los resultados desde el inicio
    this.page = 1;
    this.cargarCanchas();
  }

  // Limpia el buscador y vuelve a cargar todas las canchas
  limpiarBusqueda(): void {
    this.searchTerm = '';
    this.page = 1;
    this.cargarCanchas();
  }

  // ============================================================
  // PAGINACIÓN
  // ============================================================
  // Calculamos el número total de páginas dividiendo totalItems / pageSize
  get totalPages(): number {
    return Math.ceil(this.totalItems / this.pageSize);
  }

  // Genera un array [1, 2, 3, ...] para hacer *ngFor en los botones de página
  get pageNumbers(): number[] {
    return Array.from({ length: this.totalPages }, (_, i) => i + 1);
  }

  // Ir a una página específica
  irAPagina(pagina: number): void {
    if (pagina >= 1 && pagina <= this.totalPages) {
      this.page = pagina;
      this.cargarCanchas();
    }
  }

  paginaSiguiente(): void { this.irAPagina(this.page + 1); }
  paginaAnterior(): void { this.irAPagina(this.page - 1); }

  // ============================================================
  // MODAL DE CREAR / EDITAR CANCHA (Solo Admin)
  // ============================================================

  // Abre el modal para CREAR una nueva cancha
  abrirModalCrear(): void {
    this.editingId = null; // null = modo Crear
    this.modalTitle = 'Nueva Cancha';
    this.canchaForm.reset(); // Limpia el formulario
    this.showModal = true;
  }

  // Abre el modal para EDITAR una cancha existente
  abrirModalEditar(cancha: Cancha): void {
    this.editingId = cancha.id; // Guardamos el Id de la cancha a editar
    this.modalTitle = 'Editar Cancha';
    // Llenamos el formulario con los datos actuales de la cancha
    this.canchaForm.patchValue({
      nombre: cancha.nombre,
      descripcion: cancha.descripcion,
      precioPorHora: cancha.precioPorHora
    });
    this.showModal = true;
  }

  // Cierra el modal
  cerrarModal(): void {
    this.showModal = false;
    this.editingId = null;
    this.canchaForm.reset();
  }

  // Guarda (Crear o Editar) dependiendo de editingId
  guardarCancha(): void {
    if (this.canchaForm.invalid) return;
    this.isSaving = true;

    const datos = this.canchaForm.value;

    if (this.editingId === null) {
      // ===== MODO CREAR =====
      // Llamamos a POST /api/canchas
      this.canchasService.createCancha(datos).subscribe({
        next: () => {
          this.isSaving = false;
          this.cerrarModal();
          this.mostrarExito('¡Cancha creada exitosamente!');
          this.cargarCanchas(); // Recargamos la tabla con la nueva cancha
        },
        error: (err) => {
          this.isSaving = false;
          this.mostrarError(err.error?.mensaje || 'Error al crear la cancha.');
        }
      });
    } else {
      // ===== MODO EDITAR =====
      // Llamamos a PUT /api/canchas/{id}
      this.canchasService.updateCancha(this.editingId, datos).subscribe({
        next: () => {
          this.isSaving = false;
          this.cerrarModal();
          this.mostrarExito('¡Cancha actualizada correctamente!');
          this.cargarCanchas(); // Recargamos para ver los cambios reflejados
        },
        error: (err) => {
          this.isSaving = false;
          this.mostrarError(err.error?.mensaje || 'Error al actualizar.');
        }
      });
    }
  }

  // ============================================================
  // ELIMINAR CANCHA (Solo Admin)
  // ============================================================

  // Abre el modal de confirmación antes de eliminar
  confirmarEliminar(cancha: Cancha): void {
    this.deletingCancha = cancha; // Guardamos la cancha que se quiere eliminar
    this.showDeleteModal = true;
  }

  // Cancela la eliminación y cierra el modal
  cancelarEliminar(): void {
    this.deletingCancha = null;
    this.showDeleteModal = false;
  }

  // Ejecuta la eliminación real después de la confirmación
  eliminarCancha(): void {
    if (!this.deletingCancha) return;
    this.isDeleting = true;

    // Llamamos a DELETE /api/canchas/{id}
    this.canchasService.deleteCancha(this.deletingCancha.id).subscribe({
      next: () => {
        this.isDeleting = false;
        this.showDeleteModal = false;
        this.mostrarExito(`"${this.deletingCancha?.nombre}" eliminada correctamente.`);
        this.deletingCancha = null;
        // Si era la única cancha de esta página, volvemos a la anterior
        if (this.canchas.length === 1 && this.page > 1) { this.page--; }
        this.cargarCanchas();
      },
      error: (err) => {
        this.isDeleting = false;
        this.mostrarError('Error al eliminar la cancha.');
      }
    });
  }

  // ============================================================
  // RESERVAR CANCHA (Solo Cliente)
  // ============================================================
  abrirModalReservar(cancha: Cancha): void {
    this.selectedCancha = cancha;
    this.reservaForm.reset();

    // Prefill: hoy
    const hoy = new Date();
    const hoyStr = hoy.getFullYear() + '-' + String(hoy.getMonth() + 1).padStart(2, '0') + '-' + String(hoy.getDate()).padStart(2, '0');

    // Prefill: siguiente hora redonda
    let nextHour = hoy.getHours() + 1;
    if (nextHour > 22) {
      nextHour = 8; // Reset to 8 AM next day if late
      const manana = new Date();
      manana.setDate(manana.getDate() + 1);
      const mananaStr = manana.getFullYear() + '-' + String(manana.getMonth() + 1).padStart(2, '0') + '-' + String(manana.getDate()).padStart(2, '0');
      this.reservaForm.patchValue({ fecha: mananaStr });
    } else {
      this.reservaForm.patchValue({ fecha: hoyStr });
    }

    const nextHourStr = String(nextHour).padStart(2, '0') + ':00';
    const endHourStr = String(nextHour + 1).padStart(2, '0') + ':00';

    this.reservaForm.patchValue({
      horaInicio: nextHourStr,
      horaFin: endHourStr
    });

    this.showReservaModal = true;
  }

  cerrarReservaModal(): void {
    this.showReservaModal = false;
    this.selectedCancha = null;
    this.reservaForm.reset();
  }

  confirmarReserva(): void {
    if (this.reservaForm.invalid || !this.selectedCancha) return;

    const val = this.reservaForm.value;

    // Crear objetos Date para comparar y enviar
    const fechaInicio = new Date(`${val.fecha}T${val.horaInicio}:00`);
    const fechaFin = new Date(`${val.fecha}T${val.horaFin}:00`);
    const ahora = new Date();

    // Validación 1: Hora inicio debe ser menor que hora fin
    if (fechaInicio >= fechaFin) {
      this.mostrarError('La hora de inicio debe ser anterior a la hora de fin.');
      return;
    }

    // Validación 2: Fecha inicio no debe ser en el pasado
    if (fechaInicio < ahora) {
      this.mostrarError('La reserva no puede ser en el pasado. Elige una fecha y hora futura.');
      return;
    }

    const nuevaReserva: ReservaCreate = {
      canchaId: this.selectedCancha.id,
      fechaInicio: fechaInicio.toISOString(),
      fechaFin: fechaFin.toISOString()
    };

    this.isLoading = true;
    this.reservasService.createReserva(nuevaReserva).subscribe({
      next: () => {
        this.isLoading = false;
        this.cerrarReservaModal();
        this.mostrarExito('¡Reserva creada! Revisa "Mis Reservas" para verla.');
      },
      error: (err) => {
        this.isLoading = false;
        this.mostrarError(err.error?.mensaje || 'Error al reservar. Puede que ese horario ya esté ocupado.');
      }
    });
  }

  // ============================================================
  // UTILIDADES DE MENSAJES
  // ============================================================

  // Muestra un mensaje de éxito que desaparece solo después de 3.5 segundos
  private mostrarExito(mensaje: string): void {
    this.mensajeExito = mensaje;
    this.mensajeError = ''; // Limpiamos cualquier error previo
    setTimeout(() => this.mensajeExito = '', 3500);
  }

  // Muestra un mensaje de error que desaparece solo después de 4 segundos
  private mostrarError(mensaje: string): void {
    this.mensajeError = mensaje;
    this.mensajeExito = ''; // Limpiamos cualquier éxito previo
    setTimeout(() => this.mensajeError = '', 4000);
  }

  // Formatea el precio en pesos colombianos: 80000 → "$80.000/hr"
  formatearPrecio(precio: number): string {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0
    }).format(precio) + '/hr';
  }
}
<!-- ================================================================
     canchas-list.component.html — Vista del listado de Canchas
     ================================================================ -->

<div class="page-container fade-in-up">

  <!-- ============================================================
       ENCABEZADO Y ACCIONES PRINCIPALES
       ============================================================ -->
  <div class="d-flex justify-content-between align-items-center mb-4 flex-wrap gap-3">
    <div>
      <h1 class="page-title"><i class="bi bi-grid-3x3-gap me-2 text-primary-green"></i>Canchas Disponibles</h1>
      <p class="text-secondary mb-0">Explora y reserva tu espacio deportivo</p>
    </div>

    <!-- Acciones (Buscador y Botón Nueva Cancha) -->
    <div class="d-flex gap-2">
      <!-- Buscador (Input + Botones) -->
      <div class="input-group search-group">
        <span class="input-group-text bg-transparent border-end-0"><i class="bi bi-search text-muted"></i></span>
        <input type="text"
               class="form-control border-start-0"
               placeholder="Buscar por nombre..."
               [(ngModel)]="searchTerm"
               (keyup.enter)="buscar()">
        <button class="btn btn-outline-secondary" type="button" (click)="buscar()">Buscar</button>
        <button class="btn btn-outline-secondary btn-clear" type="button" *ngIf="searchTerm" (click)="limpiarBusqueda()">
          <i class="bi bi-x"></i>
        </button>
      </div>

      <!-- Botón Nueva Cancha — *ngIf restringe que solo lo vea el Admin -->
      <button *ngIf="userRole === 'Admin'"
              class="btn btn-success d-flex align-items-center gap-2"
              (click)="abrirModalCrear()">
        <i class="bi bi-plus-circle"></i> <span>Nueva Cancha</span>
      </button>
    </div>
  </div>

  <!-- ============================================================
       ALERTAS DE FEEDBACK (Éxito / Error)
       ============================================================ -->
  <div class="alert alert-success fade-in-up" *ngIf="mensajeExito">
    <i class="bi bi-check-circle-fill me-2"></i>{{ mensajeExito }}
  </div>
  <div class="alert alert-danger fade-in-up" *ngIf="mensajeError">
    <i class="bi bi-exclamation-triangle-fill me-2"></i>{{ mensajeError }}
  </div>

  <!-- ============================================================
       ESTADO DE CARGA (SPINNER)
       ============================================================ -->
  <div class="text-center py-5" *ngIf="isLoading">
    <div class="spinner-border text-success" style="width: 3rem; height: 3rem;" role="status">
      <span class="visually-hidden">Cargando...</span>
    </div>
    <p class="text-muted mt-3">Cargando canchas...</p>
  </div>

  <!-- ============================================================
       VISTA CUANDO NO HAY CANCHAS
       ============================================================ -->
  <div class="card card-dark text-center py-5 fade-in-up" *ngIf="!isLoading && canchas.length === 0">
    <div class="card-body">
      <i class="bi bi-inbox icon-hero text-muted mb-3"></i>
      <h3 class="text-white">No se encontraron canchas</h3>
      <p class="text-secondary">Intenta buscar con otro término o agrega una nueva si eres administrador.</p>
    </div>
  </div>

  <!-- ============================================================
       TABLA DE CANCHAS (Se muestra si hay datos)
       ============================================================ -->
  <div class="card card-dark fade-in-up" *ngIf="!isLoading && canchas.length > 0">
    <div class="table-responsive">
      <table class="table table-hover mb-0 align-middle">
        <thead>
          <tr>
            <th scope="col" style="width: 5%">ID</th>
            <th scope="col" style="width: 30%">Nombre</th>
            <th scope="col" style="width: 40%">Descripción</th>
            <th scope="col" style="width: 15%">Precio</th>
            <th scope="col" style="width: 10%" class="text-center">Acciones</th>
          </tr>
        </thead>
        <tbody>
          <!-- *ngFor itera sobre el array "canchas" y crea un <tr> por cada una -->
          <tr *ngFor="let cancha of canchas">
            <td><span class="text-muted">#{{ cancha.id }}</span></td>
            <td class="fw-bold text-white">{{ cancha.nombre }}</td>
            <td>
              <!-- text-truncate corta el texto largo con "..." -->
              <div class="text-truncate" style="max-width: 300px;" [title]="cancha.descripcion">
                {{ cancha.descripcion || 'Sin descripción' }}
              </div>
            </td>
            <!-- Usamos nuestro método formatearPrecio para mostrarlo como moneda local -->
            <td class="price-tag">{{ formatearPrecio(cancha.precioPorHora) }}</td>
            
            <td class="text-center">
              <!-- ACCIONES PARA CLIENTE -->
              <button *ngIf="userRole !== 'Admin'"
                      class="btn btn-sm btn-outline-success rounded-pill px-3"
                      (click)="abrirModalReservar(cancha)"
                      title="Reservar cancha">
                <i class="bi bi-calendar-plus me-1"></i> Reservar
              </button>

              <!-- ACCIONES PARA ADMIN -->
              <div class="d-flex gap-2 justify-content-center" *ngIf="userRole === 'Admin'">
                <!-- Botón Editar (abre modal) -->
                <button class="btn btn-sm btn-outline-info" (click)="abrirModalEditar(cancha)" title="Editar">
                  <i class="bi bi-pencil-square"></i>
                </button>
                <!-- Botón Eliminar (abre modal de confirmación) -->
                <button class="btn btn-sm btn-outline-danger" (click)="confirmarEliminar(cancha)" title="Eliminar">
                  <i class="bi bi-trash3"></i>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <!-- ============================================================
         PAGINACIÓN
         ============================================================ -->
    <div class="card-footer border-top border-secondary bg-transparent d-flex justify-content-between align-items-center py-3">
      <div class="text-muted small">
        Mostrando página <span class="fw-bold text-white">{{ page }}</span> de <span class="fw-bold text-white">{{ totalPages }}</span>
        (Total: {{ totalItems }} canchas)
      </div>
      
      <!-- Controles de Paginación Bootstrap -->
      <ul class="pagination pagination-sm mb-0">
        <li class="page-item" [class.disabled]="page === 1">
          <button class="page-link" (click)="paginaAnterior()">Anterior</button>
        </li>
        <!-- Mostramos los números de página -->
        <li class="page-item" *ngFor="let p of pageNumbers" [class.active]="p === page">
          <button class="page-link" (click)="irAPagina(p)">{{ p }}</button>
        </li>
        <li class="page-item" [class.disabled]="page === totalPages || totalPages === 0">
          <button class="page-link" (click)="paginaSiguiente()">Siguiente</button>
        </li>
      </ul>
    </div>
  </div>

</div><!-- fin page-container -->

<!-- ================================================================
     MODAL DE CREAR / EDITAR CANCHA (Solo Admin)
     ================================================================
     Es un div con position: fixed que cubre toda la pantalla.
     Solo se muestra cuando showModal es true.
     ================================================================ -->
<div class="modal-backdrop fade show" *ngIf="showModal"></div>
<div class="modal fade show d-block" tabindex="-1" *ngIf="showModal">
  <div class="modal-dialog modal-dialog-centered">
    <div class="modal-content card-dark">
      
      <div class="modal-header border-bottom border-secondary">
        <h5 class="modal-title"><i class="bi bi-building me-2 text-primary-green"></i>{{ modalTitle }}</h5>
        <!-- Botón de cerrar modal -->
        <button type="button" class="btn-close btn-close-white" (click)="cerrarModal()" aria-label="Close"></button>
      </div>

      <div class="modal-body">
        <form [formGroup]="canchaForm" (ngSubmit)="guardarCancha()">
          
          <!-- Nombre -->
          <div class="mb-3">
            <label class="form-label">Nombre de la Cancha <span class="text-danger">*</span></label>
            <input type="text" class="form-control" formControlName="nombre" placeholder="Ej: Cancha Principal">
            <div class="text-danger small mt-1" *ngIf="f['nombre'].touched && f['nombre'].invalid">
              El nombre es obligatorio.
            </div>
          </div>

          <!-- Descripción -->
          <div class="mb-3">
            <label class="form-label">Descripción</label>
            <textarea class="form-control" formControlName="descripcion" rows="3" placeholder="Detalles de la cancha..."></textarea>
          </div>

          <!-- Precio -->
          <div class="mb-3">
            <label class="form-label">Precio por Hora (COP) <span class="text-danger">*</span></label>
            <div class="input-group">
              <span class="input-group-text bg-transparent border-end-0 text-muted">$</span>
              <input type="number" class="form-control border-start-0" formControlName="precioPorHora" placeholder="Ej: 80000">
            </div>
            <div class="text-danger small mt-1" *ngIf="f['precioPorHora'].touched && f['precioPorHora'].invalid">
              Ingresa un precio válido mayor a 0.
            </div>
          </div>

          <div class="d-flex justify-content-end gap-2 mt-4">
            <button type="button" class="btn btn-outline-secondary" (click)="cerrarModal()">Cancelar</button>
            <button type="submit" class="btn btn-success" [disabled]="canchaForm.invalid || isSaving">
              <span *ngIf="isSaving" class="spinner-border spinner-border-sm me-2"></span>
              {{ isSaving ? 'Guardando...' : 'Guardar' }}
            </button>
          </div>

        </form>
      </div>
    </div>
  </div>
</div>

<!-- ================================================================
     MODAL DE CONFIRMACIÓN DE ELIMINACIÓN
     ================================================================ -->
<div class="modal-backdrop fade show" *ngIf="showDeleteModal"></div>
<div class="modal fade show d-block" tabindex="-1" *ngIf="showDeleteModal">
  <div class="modal-dialog modal-dialog-centered modal-sm">
    <div class="modal-content card-dark text-center p-4">
      
      <i class="bi bi-exclamation-octagon text-danger mb-3" style="font-size: 3rem;"></i>
      <h5 class="text-white mb-3">¿Eliminar Cancha?</h5>
      <p class="text-secondary mb-4">
        Estás a punto de eliminar <strong>{{ deletingCancha?.nombre }}</strong>.<br>
        Esta acción no se puede deshacer.
      </p>

      <div class="d-flex gap-2 w-100">
        <button type="button" class="btn btn-outline-secondary w-50" (click)="cancelarEliminar()" [disabled]="isDeleting">Cancelar</button>
        <button type="button" class="btn btn-danger w-50" (click)="eliminarCancha()" [disabled]="isDeleting">
          <span *ngIf="isDeleting" class="spinner-border spinner-border-sm me-2"></span>
          Eliminar
        </button>
      </div>

    </div>
  </div>
</div>

<!-- ================================================================
     MODAL DE RESERVAR CANCHA (Solo Cliente)
     ================================================================ -->
<div class="modal-backdrop fade show" *ngIf="showReservaModal"></div>
<div class="modal fade show d-block" tabindex="-1" *ngIf="showReservaModal">
  <div class="modal-dialog modal-dialog-centered">
    <div class="modal-content card-dark">
      
      <div class="modal-header border-bottom border-secondary">
        <h5 class="modal-title">
          <i class="bi bi-calendar-event me-2 text-primary-green"></i>Reservar Cancha
        </h5>
        <button type="button" class="btn-close btn-close-white" (click)="cerrarReservaModal()" aria-label="Close"></button>
      </div>

      <div class="modal-body">
        <div class="text-center mb-4">
          <h4 class="text-white mb-1">{{ selectedCancha?.nombre }}</h4>
          <p class="text-muted small mb-0">
            Tarifa: <span class="text-primary-green fw-bold">{{ selectedCancha ? formatearPrecio(selectedCancha.precioPorHora) : '' }}</span>
          </p>
        </div>

        <form [formGroup]="reservaForm" (ngSubmit)="confirmarReserva()">
          
          <!-- Fecha -->
          <div class="mb-3">
            <label class="form-label text-secondary small">Fecha de la Reserva</label>
            <div class="input-group">
              <span class="input-group-text bg-transparent border-end-0 text-muted">
                <i class="bi bi-calendar"></i>
              </span>
              <input type="date" class="form-control border-start-0 text-white" formControlName="fecha">
            </div>
            <div class="text-danger small mt-1" *ngIf="reservaForm.controls['fecha'].touched && reservaForm.controls['fecha'].invalid">
              La fecha es obligatoria.
            </div>
          </div>

          <div class="row">
            <!-- Hora Inicio -->
            <div class="col-md-6 mb-3">
              <label class="form-label text-secondary small">Hora de Inicio</label>
              <div class="input-group">
                <span class="input-group-text bg-transparent border-end-0 text-muted">
                  <i class="bi bi-clock"></i>
                </span>
                <select class="form-select border-start-0 text-white bg-dark" formControlName="horaInicio">
                  <option value="06:00">06:00 AM</option>
                  <option value="07:00">07:00 AM</option>
                  <option value="08:00">08:00 AM</option>
                  <option value="09:00">09:00 AM</option>
                  <option value="10:00">10:00 AM</option>
                  <option value="11:00">11:00 AM</option>
                  <option value="12:00">12:00 PM</option>
                  <option value="13:00">01:00 PM</option>
                  <option value="14:00">02:00 PM</option>
                  <option value="15:00">03:00 PM</option>
                  <option value="16:00">04:00 PM</option>
                  <option value="17:00">05:00 PM</option>
                  <option value="18:00">06:00 PM</option>
                  <option value="19:00">07:00 PM</option>
                  <option value="20:00">08:00 PM</option>
                  <option value="21:00">09:00 PM</option>
                  <option value="22:00">10:00 PM</option>
                  <option value="23:00">11:00 PM</option>
                </select>
              </div>
            </div>

            <!-- Hora Fin -->
            <div class="col-md-6 mb-3">
              <label class="form-label text-secondary small">Hora de Fin</label>
              <div class="input-group">
                <span class="input-group-text bg-transparent border-end-0 text-muted">
                  <i class="bi bi-clock-fill"></i>
                </span>
                <select class="form-select border-start-0 text-white bg-dark" formControlName="horaFin">
                  <option value="07:00">07:00 AM</option>
                  <option value="08:00">08:00 AM</option>
                  <option value="09:00">09:00 AM</option>
                  <option value="10:00">10:00 AM</option>
                  <option value="11:00">11:00 AM</option>
                  <option value="12:00">12:00 PM</option>
                  <option value="13:00">01:00 PM</option>
                  <option value="14:00">02:00 PM</option>
                  <option value="15:00">03:00 PM</option>
                  <option value="16:00">04:00 PM</option>
                  <option value="17:00">05:00 PM</option>
                  <option value="18:00">06:00 PM</option>
                  <option value="19:00">07:00 PM</option>
                  <option value="20:00">08:00 PM</option>
                  <option value="21:00">09:00 PM</option>
                  <option value="22:00">10:00 PM</option>
                  <option value="23:00">11:00 PM</option>
                  <option value="23:59">11:59 PM</option>
                </select>
              </div>
            </div>
          </div>

          <div class="d-flex justify-content-end gap-2 mt-4">
            <button type="button" class="btn btn-outline-secondary" (click)="cerrarReservaModal()">Cancelar</button>
            <button type="submit" class="btn btn-success" [disabled]="reservaForm.invalid || isLoading">
              <span *ngIf="isLoading" class="spinner-border spinner-border-sm me-2"></span>
              Confirmar Reserva
            </button>
          </div>

        </form>
      </div>
    </div>
  </div>
</div>
